void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    ret = texture(sampler_main, vUv).xyz;
    ret = ret*1.5 - 0.1;

    vec4 g;
    vec3 d = vec3(uTexSize.zw * 4, 0);
    g.x = lum(GetBlur1(vUv + d.xz));
    g.y = lum(GetBlur1(vUv - d.xz));
    g.z = lum(GetBlur1(vUv + d.zy));
    g.w = lum(GetBlur1(vUv - d.zy));

    ret *= 0.7;
    ret.x += clamp01(g.x-g.y)*5;
    ret.z += clamp01(g.y-g.x)*5;
    //ret.xy += (g.xz-g.yw)*3;

ret.x = GetBlur1(vUv).x*2;
ret.z = GetBlur2(vUv).z*3;
ret += pow(texture(sampler_main, vec2(vUv.x,1-vUv.y)).yyy+texture(sampler_main, 1-vUv).yyy,vec3(2.6,.5,.5));

  fragColor = ret;
}
